        "#page-voz #vsT0,#page-voz #vsT1{border-radius:999px!important;padding:8px 18px!important;font-weight:600!important;transition:background .15s,border-color .15s,transform .1s!important}"
        "#page-voz #vsT0{background:linear-gradient(135deg,#6366f1,#a855f7)!important;color:#fff!important;border:1px solid rgba(255,255,255,.14)!important}"
        "#page-voz #vsT1{background:rgba(255,255,255,.05)!important;color:var(--m)!important;border:1px solid rgba(148,163,184,.24)!important}"
        "</style>"
        "<script id=\"vf-premium-proc-script\">"
        "(function(){"
        "if(window.__vfPremiumProcInit) return; window.__vfPremiumProcInit=true;"
        "var _VFP={};"
        "var _PG={video:'video',imagenes:'imagen',render:'render',guion:'guion'};"
        "var _LB={video:'Video IA',imagenes:'Imagenes',render:'Render',guion:'Guion',voz:'Voz'};"
        "function _mkSt(k){return{open:false,kind:k,subkind:'',title:'',sub:'',phase:'',metrics:'',lines:[],done:false,nextPoll:null,lastOffset:0,lastProject:'',provider:'grok',showActions:false,renderJobId:'',renderPoll:null,flowSince:0,pct:null,renderUi:'work',renderDl:'',renderErr:'',originPage:'',el:null,autoCloseTimer:null,_wskSeen:false,_flwSeen:false};}"
        "function _ak(){var ks=Object.keys(_VFP);for(var i=ks.length-1;i>=0;i--){if(_VFP[ks[i]].open&&!_VFP[ks[i]].done)return ks[i];}for(var j=ks.length-1;j>=0;j--){if(_VFP[ks[j]].open)return ks[j];}return ks[ks.length-1]||'render';}"
        "function syncRenderBodyFlag(){var on=Object.keys(_VFP).some(function(k){return _VFP[k].open&&_VFP[k].kind==='render';});try{document.body.classList.toggle('vf-proc-render-on',on);}catch(e){}}"
        "function _stack(){}"
        "function _syncChipBar(k){"
        "  var bar=document.getElementById('vfbar-chip-'+k);"
        "  if(!bar) return;"
        "  var card=document.getElementById('vfc-'+k);"
        "  var exp=card&&card.classList.contains('vf-expanded');"
        "  bar.style.opacity=exp?'0':'1';"
        "}"
        "function _vfToggle(k){"
        "  var card=document.getElementById('vfc-'+k);"
        "  var arr=document.getElementById('vfarr-'+k);"
        "  var ov=document.getElementById('vfov-'+k);"
        "  if(!card||!ov) return;"
        "  var isExp=card.classList.contains('vf-expanded');"
        "  if(isExp){"
        "    card.classList.remove('vf-expanded');"
        "    ov.classList.remove('vf-open-detail');"
        "    if(arr) arr.textContent='\\u25b2';"
        "  } else {"
        "    Object.keys(_VFP).forEach(function(other){"
        "      if(other===k) return;"
        "      var oc=document.getElementById('vfc-'+other);"
        "      var oo=document.getElementById('vfov-'+other);"
        "      var oa=document.getElementById('vfarr-'+other);"
        "      if(oc) oc.classList.remove('vf-expanded');"
        "      if(oo) oo.classList.remove('vf-open-detail');"
        "      if(oa) oa.textContent='\\u25b2';"
        "      _syncChipBar(other);"
        "    });"
        "    card.classList.add('vf-expanded');"
        "    ov.classList.add('vf-open-detail');"
        "    if(arr) arr.textContent='\\u25bc';"
        "  }"
        "  _syncChipBar(k);"
        "  setTimeout(_stack,30);"
        "}"
        "function _mk(kind){"
        "  var w=document.createElement('div');"
        "  w.id='vfov-'+kind; w.className='vf-proc-overlay';"
        "  var h='<div class=\"vf-proc-card\" id=\"vfc-'+kind+'\">'+'<div id=\"vfw-'+kind+'\">'+'<div class=\"vf-proc-k\" id=\"vfk-'+kind+'\">En curso</div>'+'<div class=\"vf-proc-t\" id=\"vft-'+kind+'\">Preparando...</div>'+'<div class=\"vf-proc-s\" id=\"vfs-'+kind+'\"></div>'+'<div class=\"vf-proc-met\" id=\"vfm-'+kind+'\"></div>'+'<div class=\"vf-proc-bar\" id=\"vfbar-'+kind+'\"><div class=\"vf-proc-bar-fill\" id=\"vfbf-'+kind+'\"></div></div>'+'<div class=\"vf-proc-log\" id=\"vflog-'+kind+'\">Inicializando...</div>'+'<div class=\"vf-proc-actions\"><button class=\"vf-proc-btn stop\" id=\"vfstop-'+kind+'\" style=\"display:none\">Detener</button><button class=\"vf-proc-btn\" id=\"vfopen-'+kind+'\" style=\"display:none\">Carpeta</button><button class=\"vf-proc-btn main\" id=\"vfnext-'+kind+'\" style=\"display:none\">Siguiente</button></div></div>'+'<div id=\"vfd-'+kind+'\" style=\"display:none;text-align:center;padding:6px 0\"><div class=\"vf-proc-okmark\">&#10003;</div><div class=\"vf-proc-k\" style=\"margin-top:4px\">Listo</div><div class=\"vf-proc-t\" id=\"vfdt-'+kind+'\" style=\"margin-top:6px;font-size:15px\">Completado.</div><div id=\"vfderr-'+kind+'\" style=\"display:none;color:#fca5a5;font-size:12px;margin-top:8px\"></div><a class=\"vf-proc-btn main\" id=\"vfdl-'+kind+'\" href=\"#\" style=\"display:none;margin-top:12px\">Descargar MP4</a><div style=\"display:flex;gap:8px;justify-content:center;margin-top:14px\"><button class=\"vf-proc-btn back\" id=\"vfclose-'+kind+'\">Cerrar</button><button class=\"vf-proc-btn\" id=\"vffolder-'+kind+'\">Carpeta</button><button class=\"vf-proc-btn main\" id=\"vfdn-'+kind+'\">Siguiente</button></div></div></div>'+'<div class=\"vf-proc-chip\" id=\"vfchip-'+kind+'\"><div class=\"vf-chip-dot\" id=\"vfdot-'+kind+'\"></div><div class=\"vf-chip-info\"><div class=\"vf-chip-label\" id=\"vflbl-'+kind+'\">Generacion</div><div class=\"vf-chip-status\" id=\"vfcst-'+kind+'\">Iniciando...</div></div><div class=\"vf-chip-pct\" id=\"vfpct-'+kind+'\">-</div><div class=\"vf-chip-expand\" id=\"vfarr-'+kind+'\">&#9650;</div><div class=\"vf-chip-bar\" id=\"vfbar-chip-'+kind+'\"><div class=\"vf-chip-bar-fill ind\" id=\"vfcbar-'+kind+'\"></div></div></div>';"
        "  w.innerHTML=h;"
        "  var _stk=document.getElementById('vf-proc-stack');"
        "  if(!_stk){_stk=document.createElement('div');_stk.id='vf-proc-stack';document.body.appendChild(_stk);}"
        "  _stk.appendChild(w);"
        "  var s=_VFP[kind];"
        "  document.getElementById('vfchip-'+kind).addEventListener('click',function(){_vfToggle(kind);});"
        "  var bs=document.getElementById('vfstop-'+kind); if(bs) bs.onclick=function(){try{var _st=_VFP[kind];if(_st){if(_st.nextPoll){clearTimeout(_st.nextPoll);_st.nextPoll=null;}_st.open=false;}if(_st&&_st.subkind==='flow'){fetch('/api/flow/stop',{method:'POST'});}else if(window.vfStopCurrent){window.vfStopCurrent();}else{fetch('/api/grok/detener',{method:'POST'});}}catch(e){}_done(kind,'Detenido.');_hide(kind);};"
        "  var bo=document.getElementById('vfopen-'+kind); if(bo) bo.onclick=function(){openFolder();};"
        "  var bn=document.getElementById('vfnext-'+kind); if(bn) bn.onclick=function(){goNext();};"
        "  var bc=document.getElementById('vfclose-'+kind); if(bc) bc.onclick=function(){var s=_VFP[kind];if(s&&s.autoCloseTimer){clearTimeout(s.autoCloseTimer);s.autoCloseTimer=null;}_hide(kind);};"
        "  var bfo=document.getElementById('vffolder-'+kind); if(bfo) bfo.onclick=function(){openRenderFinalFolder();};"
        "  var bdn=document.getElementById('vfdn-'+kind); if(bdn) bdn.onclick=function(){goNext();};"
        "  return w;"
        "}"
        "function _ensure(kind){if(!_VFP[kind])_VFP[kind]=_mkSt(kind);var s=_VFP[kind];if(!s.el||!document.getElementById('vfov-'+kind))s.el=_mk(kind);return s;}"
        "function _paint(kind){var s=_VFP[kind];if(!s)return;var w=s.el;if(!w){_ensure(kind);w=s.el;}if(!w)return;w.classList.toggle('on',!!s.open);if(!s.open)return;var card=document.getElementById('vfc-'+kind);var isD=s.done&&(s.renderUi==='done'||s.kind!=='render');var wk=document.getElementById('vfw-'+kind),dn=document.getElementById('vfd-'+kind);if(wk)wk.style.display=isD?'none':'block';if(dn)dn.style.display=isD?'block':'none';if(card)card.classList.toggle('vf-proc-done',!!isD);if(!isD){var ek=document.getElementById('vfk-'+kind);if(ek)ek.textContent='En curso';var et=document.getElementById('vft-'+kind);if(et)et.textContent=s.title||'Procesando...';var es=document.getElementById('vfs-'+kind);if(es)es.textContent=(s.kind==='render'&&s.renderUi==='work')?'':(s.phase||s.sub||'');var em=document.getElementById('vfm-'+kind);if(em)em.textContent=(s.kind==='render'&&s.renderUi==='work')?'':(s.metrics||'');var bstop=document.getElementById('vfstop-'+kind);if(bstop)bstop.style.display=(s.kind==='video'||s.kind==='imagenes')?'inline-flex':'none';var bop=document.getElementById('vfopen-'+kind),bnx=document.getElementById('vfnext-'+kind);var sa=!!(s.open&&s.done);if(bop)bop.style.display=sa?'inline-flex':'none';if(bnx)bnx.style.display=sa?'inline-flex':'none';var log=document.getElementById('vflog-'+kind);if(log){if(s.kind==='render'&&s.renderUi==='work'){var trl=document.getElementById('logTerminal');var rawL=(String(s.phase||'').trim()||(trl&&trl.__vfLastSnap)||(trl&&(trl.textContent||'')||''));log.textContent=simplifyRenderMessage(String(rawL).replace(/\\s+/g,' '),s.pct)||'Preparando proyecto…';}else{var txt=s.lines.slice(-14).join('\\n')||'Inicializando...';log.textContent=txt;log.scrollTop=log.scrollHeight;}}var br=document.getElementById('vfbar-'+kind),bf=document.getElementById('vfbf-'+kind);if(br&&bf){if(s.pct!=null&&!isNaN(s.pct)){br.classList.remove('ind');bf.style.width=Math.max(2,Math.min(100,s.pct))+'%';}else{br.classList.add('ind');bf.style.width='36%';}}}"
        "var dot=document.getElementById('vfdot-'+kind),lbl=document.getElementById('vflbl-'+kind),cst=document.getElementById('vfcst-'+kind),pe=document.getElementById('vfpct-'+kind),cb=document.getElementById('vfcbar-'+kind);"
        "if(lbl)lbl.textContent=(_LB[s.kind]||s.title||'Generacion')+' - VideoForge';"
        "if(s.done){if(dot)dot.className='vf-chip-dot '+(s.renderErr?'err':'done');if(cst)cst.textContent=s.renderErr?'Error':'Completado';if(pe)pe.textContent='100%';if(cb){cb.style.width='100%';cb.classList.remove('ind');}}"
        "else{if(dot)dot.className='vf-chip-dot';if(cst){var trc=document.getElementById('logTerminal');var src=(String(s.phase||'').trim()||(trc&&trc.__vfLastSnap)||(trc&&(trc.textContent||'')||''));cst.textContent=s.kind==='render'&&!s.done?simplifyRenderMessage(String(src).replace(/\\s+/g,' '),s.pct).slice(0,48):String(s.phase||s.sub||'Procesando...').slice(0,38);}var pv=s.pct!=null&&!isNaN(s.pct)?Math.round(s.pct):null;if(pe)pe.textContent=pv!=null?(pv+'%'):'-';if(cb){if(pv!=null){cb.style.width=pv+'%';cb.classList.remove('ind');}else{cb.style.width='38%';cb.classList.add('ind');}}}"
        "syncRenderBodyFlag();setTimeout(_stack,30);}"
        "function show(kind,title,sub,sk){var s=_ensure(kind);s.open=true;s.done=false;s.subkind=sk||'';s.title=title||'Procesando';s.sub=sub||'';s.phase=sub||'';s.metrics='';s.lines=[];s.lastOffset=0;s.flowSince=0;s.pct=null;s.showActions=false;s.renderUi='work';s.renderDl='';s.renderErr='';s.originPage=_PG[kind]||kind||'';s._wskSeen=false;s._flwSeen=false;_paint(kind);setTimeout(function(){var c=document.getElementById('vfc-'+kind);if(c)c.classList.add('vf-expanded');var arr=document.getElementById('vfarr-'+kind);if(arr)arr.textContent='\\u25bc';if(s.el)s.el.classList.add('vf-open-detail');_syncChipBar(kind);_stack();},40);}"
        "function _done(kind,msg){"
        "  var s=_VFP[kind];if(!s)return;"
        "  s.done=true;s.pct=100;"
        "  if(msg&&s.kind!=='render')s.lines.push(msg);"
        "  if(s.kind==='render'&&s.renderUi!=='done')s.lines=[];"
        "  var label=_doneLabel(kind,msg);"
        "  var dt=document.getElementById('vfdt-'+kind);"
        "  if(dt) dt.textContent=label;"
        "  Object.keys(_VFP).forEach(function(other){"
        "    if(other===kind) return;"
        "    var oc=document.getElementById('vfc-'+other);"
        "    var oo=document.getElementById('vfov-'+other);"
        "    var oa=document.getElementById('vfarr-'+other);"
        "    if(oc) oc.classList.remove('vf-expanded');"
        "    if(oo) oo.classList.remove('vf-open-detail');"
        "    if(oa) oa.textContent='\\u25b2';"
        "  });"
        "  _paint(kind);"
        "  var card=document.getElementById('vfc-'+kind);"
        "  var arr=document.getElementById('vfarr-'+kind);"
        "  if(card) card.classList.add('vf-expanded');"
        "  if(arr) arr.textContent='\\u25bc';"
        "  if(s.el) s.el.classList.add('vf-open-detail');"
        "  _syncChipBar(kind);"
        "  Object.keys(_VFP).forEach(function(o){if(o!==kind)_syncChipBar(o);});"
        "  _vfPlayDone();"
        "  setTimeout(_stack,40);"
        "  if(s.autoCloseTimer) clearTimeout(s.autoCloseTimer);"
        "  s.autoCloseTimer=setTimeout(function(){_hide(kind);},5000);"
        "}"
        "function done(msg){var k=_ak();if(k)_done(k,msg);}"
        "function _vfPlayDone(){"
        "  try{"
        "    var ctx=new(window.AudioContext||window.webkitAudioContext)();"
        "    var t=ctx.currentTime;"
        "    var osc=ctx.createOscillator();"
        "    var gain=ctx.createGain();"
        "    osc.connect(gain); gain.connect(ctx.destination);"
        "    osc.type='sine';"
        "    osc.frequency.setValueAtTime(523,t);"
        "    osc.frequency.setValueAtTime(659,t+0.12);"
        "    osc.frequency.setValueAtTime(784,t+0.24);"
        "    gain.gain.setValueAtTime(0,t);"
        "    gain.gain.linearRampToValueAtTime(0.18,t+0.04);"
        "    gain.gain.setValueAtTime(0.18,t+0.26);"
        "    gain.gain.linearRampToValueAtTime(0,t+0.52);"
        "    osc.start(t); osc.stop(t+0.54);"
        "    osc.onended=function(){try{ctx.close();}catch(e){}};"
        "  }catch(e){}"
        "}"
        "var _DONE_LABEL={"
        "  video:'Generacion de video IA completada',"
        "  imagenes:'Generacion de imagenes completada',"
        "  render:'Render de video completado',"
        "  guion:'Guion y prompts generados',"
        "  voz:'Voz generada y fusionada'"
        "};"
        "function _doneLabel(kind,msg){"
        "  if(msg&&msg.length>4&&msg.indexOf('OK ')<0) return msg;"
        "  return _DONE_LABEL[kind]||'Proceso completado';"
        "}"
        "function _hide(kind){var s=_VFP[kind];if(!s)return;if(s.autoCloseTimer){clearTimeout(s.autoCloseTimer);s.autoCloseTimer=null;}s.open=false;s.done=false;s.renderUi='work';s.renderErr='';s.renderDl='';s.renderJobId='';s.pct=null;s.lines=[];s.title='';s.phase='';s.metrics='';s.originPage='';if(s.nextPoll){clearTimeout(s.nextPoll);s.nextPoll=null;}if(s.renderPoll){clearTimeout(s.renderPoll);s.renderPoll=null;}if(s.el)s.el.classList.remove('on','vf-open-detail');var c=document.getElementById('vfc-'+kind);if(c)c.classList.remove('vf-expanded');var arr=document.getElementById('vfarr-'+kind);if(arr)arr.textContent='\\u25b2';"
        "if(kind==='render'){var _t=document.getElementById('logTerminal');if(_t)_t.__vfAllRenderLines=[];try{buildSummaryPills();}catch(_e){}}"
        "_syncChipBar(kind);syncRenderBodyFlag();setTimeout(_stack,80);}"
        "function hide(){var k=_ak();if(k)_hide(k);}"
        "function add(line){if(!line)return;var k=_ak();if(!k)return;var s=_VFP[k];if(!s)return;s.lines.push(String(line));"
        "if(k==='render'){var _t=document.getElementById('logTerminal');if(_t){if(!_t.__vfAllRenderLines)_t.__vfAllRenderLines=[];_t.__vfAllRenderLines.push(String(line));}"
        "if(/\\[([a-z_]+)\\]\\s*Escena/.test(String(line))){try{buildSummaryPills();}catch(_bpe){}}"
        "}"
        "_paint(k);}"
        "function setRow(items){}"
        "var st={};"
        "['open','kind','subkind','title','sub','phase','metrics','lines','done','nextPoll','lastOffset','lastProject','provider','showActions','renderJobId','renderPoll','flowSince','pct','renderUi','renderDl','renderErr','originPage'].forEach(function(p){Object.defineProperty(st,p,{get:function(){var k=_ak();return k&&_VFP[k]?_VFP[k][p]:undefined;},set:function(v){var k=_ak();if(k&&_VFP[k])_VFP[k][p]=v;},enumerable:true,configurable:true});});"
        "function ingestVideoLogHints(lines){if(!lines||!lines.length)return;var s=_VFP['video'];if(!s||!s.open)return;for(var i=lines.length-1;i>=0;i--){var ln=String(lines[i]);var m=ln.match(/(\\d+)\\s*\\/\\s*(\\d+)/)||ln.match(/(\\d+)\\s+de\\s+(\\d+)/i);if(m){var a=parseInt(m[1],10),b=parseInt(m[2],10);if(b>0){s.pct=Math.min(99,Math.round(a/b*100));s.phase='Avance: '+a+'/'+b;return;}}}}"
        "function readVideoProjectFallback(){var sels=document.querySelectorAll('#page-video select.proj-select');for(var i=0;i<sels.length;i++){if(sels[i]&&sels[i].value)return sels[i].value;}var one=document.querySelector('select[id*=\"proj-select\"]');return(one&&one.value)?one.value:'';}"
        "function readRenderProject(){var s=document.querySelector('#page-render select#proj-select-render,#proj-select-render');return(s&&s.value)?s.value:readVideoProjectFallback();}"
        "function humanRenderPhase(raw,pct){var tl=String(raw||'').trim();var t=tl.toLowerCase();var p=+pct||0;if(!tl)return p>8?('Avance '+Math.round(p)+'%'):'Preparando proyecto…';"
        "if(p>=92)return 'Finalizando vídeo…';"
        "if(/listo|\\bcierre\\b|\\bmux\\b|guardando|\\bexport|\\.mp4|100\\s*%/i.test(t))return 'Últimos ajustes…';"
        "if(/whisper|transcri|subtitle|\\.srt|alineaci[oó]n|subt[ií]tul/i.test(t))return 'Transcribiendo audio…';"
        "if(/\\bffmpeg\\b|concaten|concat|xfade|mezcl|mont|c[oó]dec|filtro|\\baac\\b|h\\.?264|\\bpcm\\b/i.test(t))return 'Mezclando escenas…';"
        "if(/modal|\\bgpu\\b|\\bken\\s*burn|motion|anim(a|ándo)|zoom\\s*|clip\\s|corte\\s*v[ií]deo/i.test(t))return 'Animando tomas…';"
        "if(/escena|storyboard|\\bslide|\\bimagen(\\s+[0-9]|es)\\b|carpeta\\.\\w+|colecci[oó]n\\s+d[eé]|renderizando\\s+fotograma/i.test(t))return 'Procesando escenas…';"
        "if(/inici|cargando|colecci[oó]n(\\s+[dí]|\\b)|preparando|recolect/i.test(t))return 'Preparando proyecto…';"
        "return p>6?('Avance '+Math.round(p)+'%'):'Generando vídeo…';}"
        
        "function syncOuterRenderPage(j, err){"
        " try{"
        "  var rip=document.getElementById('renderInProgress'), rr=document.getElementById('renderResult');"
        "  if(rip) rip.style.display='none';"
        "  if(rr && j && !err){"
        "   rr.style.display='block';"
        "   var a=document.getElementById('btnDescargar');"
        "   if(a && j.video_url){ a.href=j.video_url; a.setAttribute('href', j.video_url);}"
        "   var sub=document.getElementById('resultSub'); if(sub) sub.textContent='Listo para descargar';"
        "   var ss=document.getElementById('statSize'); if(ss&&j.size_mb!=null) ss.textContent=j.size_mb+' MB';"
        "   var sd=document.getElementById('statDur'); if(sd&&j.duracion!=null) sd.textContent=String(j.duracion)+' min';"
        "   var se=document.getElementById('statEsc'); if(se&&j.escenas!=null) se.textContent=String(j.escenas);"
        "  }"
