        " var ok=document.getElementById('vfok-render'); if(ok) ok.textContent='+';"
        " var dt=document.getElementById('vfdt-render'); if(dt) dt.textContent='Tu montaje termino sin errores.';"
        " var bits=[]; if(j&&j.size_mb!=null) bits.push(j.size_mb+' MB'); if(j&&j.duracion!=null) bits.push(j.duracion+' min'); if(j&&j.escenas!=null) bits.push(j.escenas+' escenas');"
        " var dl=document.getElementById('vfdl-render');"
        " if(dl){ if(s.renderDl){ dl.href=s.renderDl; dl.style.display='inline-flex'; } else { dl.style.display='none'; }}"
        " syncOuterRenderPage(j,false);"
        " _paint('render');"
        "}"
