        " var dt=document.getElementById('vfdt-render'); if(dt) dt.textContent='Revisa audio, imagenes y el guion en la pagina de render.';"
        " var er=document.getElementById('vfderr-render'); if(er){ er.style.display='block'; er.textContent=s.renderErr; }"
        " var dl=document.getElementById('vfdl-render'); if(dl) dl.style.display='none';"
        " _paint('render');"
        "}"
