        "function urlKind(u){"
        " if(!u) return null;"
        " if(u.indexOf('/api/grok/iniciar')>=0||u.indexOf('/api/qwen/iniciar')>=0) return {k:'video',sk:'',t:'Generando videos',s:'Preparando imágenes y cola de animación…'};"
        " if(u.indexOf('/api/whisk/run-prompts')>=0) return {k:'imagenes',sk:'whisk',t:'Whisk',s:'Creando imágenes con tus cuentas Google…'};"
        " if(u.indexOf('/api/flow/run-prompts')>=0) return {k:'imagenes',sk:'flow',t:'Google Flow',s:'Generando imágenes en lote…'};"
        " if(u.indexOf('/api/pollination/generate')>=0) return {k:'imagenes',sk:'pollination',t:'Pollination',s:'Enviando prompts al webhook n8n…'};"
        " if(u.indexOf('/api/guion/n8n_proxy')>=0) return {k:'guion',sk:'',t:'Guion',s:'Procesando texto y generando prompts...'};"
        " if(u.indexOf('/api/guion/')>=0&&u.indexOf('/api/guion/cargar')<0&&u.indexOf('/api/guion/guardar')<0) return {k:'guion',sk:'',t:'Guion',s:'Procesando guion...'};"
        " if(u.indexOf('/api/voz/generar')>=0) return {k:'voz',sk:'generar',t:'Generando voz',s:'Generando fragmentos de audio...'};"
        " if(u.indexOf('/api/voz/fusionar')>=0) return {k:'voz',sk:'fusionar',t:'Fusionando voz',s:'Combinando fragmentos de audio...'};"
        " return null;"
        "}"
        "function goPage(cands){"
        " if(!Array.isArray(cands)) return false;"
        " for(var i=0;i<cands.length;i++){"
        "   var p=cands[i];"
        "   try{"
        "     if(typeof window.navigate==='function' && document.getElementById('page-'+p)){"
        "       window.navigate(p);"
        "       return true;"
        "     }"
        "   }catch(e){}"
        "   var btn=document.querySelector('.sb-item[data-page=\"'+p+'\"]');"
        "   if(btn){ btn.click(); return true; }"
        " }"
        " return false;"
        "}"
        "function goNext(){"
        " if(st.kind==='guion'){ goPage(['imagen','video','render']); }"
        " else if(st.kind==='imagenes'){ goPage(['video','render','miniaturas']); }"
        " else if(st.kind==='video'){ goPage(['render','miniaturas','home']); }"
        " else if(st.kind==='render'){ goPage(['miniaturas','home','guion']); }"
        " else { try{ window.scrollTo({top:0,behavior:'smooth'}); }catch(e){} }"
        " hide();"
        "}"
        "function openFolder(){"
        " if(st.kind==='imagenes'){"
        "  if(st.subkind==='flow'){"
        "   fetch('/api/flow/abrir_carpeta',{method:'POST',headers:{'Content-Type':'application/json'},body:'{}'})"
        "    .then(function(r){return r.json();}).then(function(j){ if(!j||j.ok===false) add('⚠ '+(j&&j.error?j.error:'No se pudo abrir la carpeta Flow')); }).catch(function(){ add('⚠ Error de red al abrir carpeta Flow'); });"
        "   return;"
        "  }"
        "  fetch('/api/whisk/abrir_carpeta',{method:'POST',headers:{'Content-Type':'application/json'},body:'{}'})"
        "   .then(function(r){return r.json();}).then(function(j){ if(!j||j.ok===false) add('⚠ '+(j&&j.error?j.error:'No se pudo abrir la carpeta de imágenes')); }).catch(function(){ add('⚠ Error de red al abrir carpeta'); });"
        "  return;"
        " }"
        " var proj=st.lastProject||readVideoProjectFallback();"
        " if(!proj){ add('⚠ Elige un proyecto en la barra superior y vuelve a intentar.'); return;}"
        " var endpoint=(st.provider==='qwen')?'/api/qwen/abrir_carpeta':'/api/grok/abrir_carpeta';"
        " fetch(endpoint,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({project:proj})})"
        "  .then(function(r){return r.json();}).then(function(j){ if(j&&j.ok===false) add('⚠ '+(j.error||'No se pudo abrir')); }).catch(function(){ add('⚠ Error de red al abrir carpeta de videos'); });"
        "}"
        "function tryPollLog(base){"
        " var kind='video';"
        " var s=_VFP[kind]; if(!s||!s.open) return;"
        " if(s.nextPoll) clearTimeout(s.nextPoll);"
        " var p=s.lastProject?('&project='+encodeURIComponent(s.lastProject)):'';"
        " var url=base+'?offset='+encodeURIComponent(s.lastOffset)+p;"
        " fetch(url).then(function(r){return r.json();}).then(function(j){"
        "   var s=_VFP[kind]; if(!s||!s.open) return;"
        "   if(Array.isArray(j.lines)){"
        "     j.lines.forEach(function(l){s.lines.push(String(l));});"
        "     s.lastOffset=(j.next_offset==null?s.lastOffset:j.next_offset);"
        "     var vd=+(j.videos_done||0), vt=+(j.videos_total||0);"
        "     if(vt>0){ s.pct=Math.min(99,Math.round(vd/Math.max(1,vt)*100)); s.phase='Videos listos en carpeta: '+vd+' / '+vt; s.metrics='Salida: carpeta video del proyecto'; }"
        "     else { ingestVideoLogHints(j.lines); }"
        "   }"
        "   _paint(kind);"
        "   if(j.finished){ _done(kind,'Animacion finalizada.'); return; }"
        "   s.nextPoll=setTimeout(function(){tryPollLog(base);}, 1200);"
        " }).catch(function(){ var s=_VFP[kind]; if(s&&s.open) s.nextPoll=setTimeout(function(){tryPollLog(base);}, 2000); });"
        "}"
        "function pollWhisk(){"
        " var kind='imagenes';"
        " var s=_VFP[kind]; if(!s||!s.open) return;"
        " if(!s._wskSeen) s._wskSeen=false;"
        " fetch('/api/whisk/status').then(function(r){return r.json();}).then(function(j){"
        "  var s=_VFP[kind]; if(!s||!s.open) return;"
        "  if(j&&j.running) s._wskSeen=true;"
        "  var logs=[];"
        "  if(j&&j.last_log&&j.last_log.length) logs=j.last_log;"
        "  else if(j&&j.log&&j.log.length) logs=j.log;"
        "  if(logs.length) logs.forEach(function(l){s.lines.push(String(l));});"
        "  var tot=+(j&&j.total!=null?j.total:0)||0, pr=+(j&&j.progress!=null?j.progress:0)||0, saved=+(j&&j.images_saved!=null?j.images_saved:0)||0;"
        "  if(tot>0){ s.pct=Math.min(99,Math.round(pr/Math.max(1,tot)*100)); s.phase='Imagenes en cola: '+pr+' / '+tot+' · guardadas '+saved; }"
        "  else { s.pct=null; s.phase=(j&&j.running)?'Iniciando workers y cuentas...':'Esperando que Whisk arranque...'; }"
        "  try{"
        "   var acc=j&&j.accounts, online=0, at=acc?acc.length:0;"
        "   if(acc){ for(var i=0;i<acc.length;i++){ if(acc[i]&&acc[i].logged_in) online++; } }"
        "   if(at) s.metrics='Cuentas: '+online+'/'+at+(j&&j.step?(' · '+j.step):'');"
        "  }catch(e){ s.metrics=''; }"
        "  _paint(kind);"
        "  if(j&&j.running){ s.nextPoll=setTimeout(pollWhisk,1100); return; }"
        "  if(!s._wskSeen){ s.nextPoll=setTimeout(pollWhisk,1500); return; }"
        "  s._wskSeen=false;"
        "  _done(kind,'Generacion de imagenes completada.');"
        " }).catch(function(){ var s=_VFP[kind]; if(s&&s.open) s.nextPoll=setTimeout(pollWhisk,2000); });"
        "}"
        "function pollFlow(){"
        " var kind='imagenes';"
        " var s=_VFP[kind]; if(!s||!s.open) return;"
        " if(!s._flwSeen) s._flwSeen=false;"
        " var since=s.flowSince||0;"
        " fetch('/api/flow/status?since='+encodeURIComponent(since)).then(function(r){return r.json();}).then(function(j){"
        "  var s=_VFP[kind]; if(!s||!s.open) return;"
        "  var nb=+(j&&j.batch_id)||0;"
        "  if(nb&&nb!==s._flwBatch){s._flwSeen=false;s._flwBatch=nb;}"
        "  if(j&&j.running) s._flwSeen=true;"
        "  if(j&&j.last_log&&j.last_log.length) j.last_log.forEach(function(l){s.lines.push(String(l));});"
        "  if(typeof j.log_total==='number') s.flowSince=j.log_total;"
        "  var tot=+(j&&j.total)||0, pr=+(j&&j.progress)||0;"
        "  if(tot>0){ s.pct=Math.min(99,Math.round(pr/Math.max(1,tot)*100)); s.phase='Flow: imagenes '+pr+'/'+tot; }"
        "  else if(j&&j.running){ s.pct=null; s.phase='Flow en ejecucion...'; }"
        "  else { s.pct=null; s.phase='Esperando que Flow arranque...'; }"
        "  _paint(kind);"
        "  if(j&&j.running){ s.nextPoll=setTimeout(pollFlow,1100); return; }"
        "  if(!s._flwSeen){ s.nextPoll=setTimeout(pollFlow,1500); return; }"
        "  s._flwSeen=false;"
        "  _done(kind,'Generacion Flow completada.');"
        " }).catch(function(){ var s=_VFP[kind]; if(s&&s.open) s.nextPoll=setTimeout(pollFlow,2000); });"
        "}"
        "function simplifyRenderMessage(raw,pct){ return humanRenderPhase(raw,pct); }"
        "function initRenderUX(){"
        " try{"
        "  if(core && !core.__vfGlyph){"
        "    core.__vfGlyph=true;"
        "    core.textContent='';"
        "    core.innerHTML='<svg class=\"vf-render-glyph\" viewBox=\"0 0 24 24\" fill=\"none\" xmlns=\"http://www.w3.org/2000/svg\"><rect x=\"3\" y=\"5\" width=\"14\" height=\"14\" rx=\"3\" stroke=\"#a78bfa\" stroke-width=\"1.7\"/><path d=\"M17 9l4-2v10l-4-2V9z\" stroke=\"#a78bfa\" stroke-width=\"1.7\" stroke-linejoin=\"round\"/><circle cx=\"10\" cy=\"12\" r=\"2.8\" fill=\"rgba(124,106,255,.65)\"/></svg>';"
        "  }"
        "  if(lbl){ lbl.style.margin='2px 0 0'; lbl.style.textAlign='center'; }"
        "  var term=document.getElementById('logTerminal');"
        "  if(term && !term.__vfSimple){"
        "    term.__vfSimple=true;"
        "    term.__vfSrcTail='';"
        "    term.__vfLastShown='';"
        "    term.__vfPainting=false;"
        "    var paint=function(){"
        "      if(term.__vfPainting) return;"
        "      var raw=(term.textContent||'').replace(/\\s+/g,' ').trim();"
        "      var pctEl=document.getElementById('renderPct');"
        "      var pct=0; if(pctEl){ var m=(pctEl.textContent||'').match(/(\\d+)/); if(m) pct=parseInt(m[1],10)||0; }"
        "      term.__vfLastSnap=raw;"
        "      var simp=simplifyRenderMessage(raw,pct);"
        "      if(term.__vfLastShown===simp&&term.__vfSrcTail===raw) return;"
        "      term.__vfSrcTail=raw;"
        "      term.__vfLastShown=simp;"
        "      term.__vfPainting=true;"
